from __future__ import annotations

import time
from collections import deque
from copy import deepcopy
from typing import Any

from fastapi import WebSocket

BACKPRESSURE_THRESHOLD = 8


class Hub:
    """WebSocket subscribers with delta broadcasts and ephemeral presence snapshots."""

    def __init__(self) -> None:
        self._rooms: dict[str, set[WebSocket]] = {}
        self._presence: dict[str, dict[str, dict[str, Any]]] = {}
        # WebSocket python id → (model_id, peer_id)
        self._socket_meta: dict[int, tuple[str, str]] = {}
        # Per-model monotonic sequence counter
        self._seq: dict[str, int] = {}
        # Per-model ring buffer: deque of (seq, ts, payload_copy)
        self._buffer: dict[str, deque[tuple[int, float, dict[str, Any]]]] = {}
        # Per-socket in-flight send depth (keyed on id(websocket))
        self._send_queue_depth: dict[int, int] = {}

    def subscribe(self, model_id: str, websocket: WebSocket) -> None:
        wsid = id(websocket)
        _, pid = self._socket_meta.get(wsid, (model_id, ""))
        self._socket_meta[wsid] = (model_id, pid)
        self._rooms.setdefault(model_id, set()).add(websocket)

    def unregister(self, websocket: WebSocket) -> None:
        wsid = id(websocket)
        self._send_queue_depth.pop(wsid, None)
        tup = self._socket_meta.pop(wsid, None)
        if not tup:
            return
        mid, peer_id = tup
        if peer_id:
            peers = self._presence.get(mid)
            if peers:
                peers.pop(peer_id, None)

        room = self._rooms.get(mid)
        if room:
            room.discard(websocket)
            if not room:
                self._rooms.pop(mid, None)

    def set_peer_id(self, websocket: WebSocket, peer_id: str) -> tuple[str | None, str]:
        wsid = id(websocket)
        tup = self._socket_meta.get(wsid)
        if tup is None:
            return None, peer_id
        mid, _ = tup
        self._socket_meta[wsid] = (mid, peer_id)
        return mid, peer_id

    def touch_presence(
        self, model_id: str, peer_id: str, patch: dict[str, Any]
    ) -> dict[str, dict[str, Any]]:
        room = self._presence.setdefault(model_id, {})

        base = dict(room.get(peer_id, {}))

        base.update(patch)

        base.setdefault("peerId", peer_id)

        room[peer_id] = base

        return room

    async def publish(self, model_id: str, payload: dict[str, Any]) -> int:
        """Stamp payload with next seq, append to ring buffer, and broadcast."""
        seq = self._seq.get(model_id, 0) + 1
        self._seq[model_id] = seq
        stamped = {**payload, "seq": seq}

        buf = self._buffer.setdefault(model_id, deque(maxlen=512))
        buf.append((seq, time.monotonic(), deepcopy(stamped)))

        await self.broadcast_json(model_id, stamped)
        return seq

    def resume(self, model_id: str, from_seq: int) -> list[dict[str, Any]] | None:
        """Return buffered payloads with seq > from_seq, or None on window miss."""
        buf = self._buffer.get(model_id)
        if not buf:
            return None

        oldest_seq = buf[0][0]
        if from_seq + 1 < oldest_seq:
            return None

        return [payload for seq, _ts, payload in buf if seq > from_seq]

    async def broadcast_presence(self, model_id: str) -> None:
        peers = dict(self._presence.get(model_id, {}))
        payload: dict[str, Any] = {
            "type": "presence_state",
            "modelId": model_id,
            "payload": {"peers": peers},
        }
        await self.broadcast_json(model_id, payload)

    async def broadcast_json(self, model_id: str, payload: dict[str, Any]) -> None:
        room = self._rooms.get(model_id)
        if not room:
            return

        stale: list[WebSocket] = []

        for ws in list(room):
            wsid = id(ws)
            depth = self._send_queue_depth.get(wsid, 0)
            if depth >= BACKPRESSURE_THRESHOLD:
                try:
                    await ws.close(code=1011)
                except Exception:
                    pass
                stale.append(ws)
                continue
            self._send_queue_depth[wsid] = depth + 1
            try:
                await ws.send_json(payload)
            except Exception:
                stale.append(ws)
            finally:
                self._send_queue_depth[wsid] = max(
                    0, self._send_queue_depth.get(wsid, 1) - 1
                )

        for ws in stale:
            self.unregister(ws)

"""API-V3-01 — Tool registry.

Every kernel verb registers a ToolDescriptor here at boot.  The registry is
in-memory and populated by calling `register()` at module import time (or from
each theme WP's own module when it lands).
"""

from __future__ import annotations

from dataclasses import dataclass
from typing import Any, Literal


@dataclass(frozen=True)
class RestEndpoint:
    method: Literal["GET", "POST"]
    path: str


@dataclass(frozen=True)
class ExitCode:
    code: int
    meaning: str


@dataclass
class ToolDescriptor:
    name: str
    category: Literal["query", "mutation", "transform", "job", "introspection"]
    inputSchema: dict[str, Any]
    outputSchema: dict[str, Any]
    exitCodes: dict[str, ExitCode]
    cliExample: str
    restEndpoint: RestEndpoint
    sideEffects: Literal["none", "mutates-kernel", "enqueues-job", "writes-audit"]
    agentSafetyNotes: str | None = None


@dataclass
class ToolCatalog:
    schemaVersion: str
    tools: list[ToolDescriptor]


_registry: dict[str, ToolDescriptor] = {}


def register(descriptor: ToolDescriptor) -> None:
    _registry[descriptor.name] = descriptor


def get_catalog() -> ToolCatalog:
    return ToolCatalog(
        schemaVersion="api-v3.0",
        tools=list(_registry.values()),
    )


def get_descriptor(name: str) -> ToolDescriptor | None:
    return _registry.get(name)


# ---------------------------------------------------------------------------
# Seed: introspection tools (registered at import time)
# ---------------------------------------------------------------------------

_COMMON_ERROR_CODES: dict[str, ExitCode] = {
    "ok": ExitCode(code=0, meaning="Success"),
    "not_found": ExitCode(code=1, meaning="Tool name not found in registry"),
    "error": ExitCode(code=1, meaning="Unexpected error"),
}

register(
    ToolDescriptor(
        name="api-list-tools",
        category="introspection",
        inputSchema={
            "$schema": "http://json-schema.org/draft-07/schema#",
            "title": "ApiListToolsInput",
            "type": "object",
            "properties": {
                "output": {
                    "type": "string",
                    "enum": ["json", "text"],
                    "default": "json",
                    "description": "Output format.",
                }
            },
            "additionalProperties": False,
        },
        outputSchema={
            "$schema": "http://json-schema.org/draft-07/schema#",
            "title": "ToolCatalog",
            "type": "object",
            "required": ["schemaVersion", "tools"],
            "properties": {
                "schemaVersion": {"type": "string"},
                "tools": {
                    "type": "array",
                    "items": {"$ref": "#/definitions/ToolDescriptor"},
                },
            },
            "definitions": {
                "ToolDescriptor": {
                    "type": "object",
                    "required": [
                        "name",
                        "category",
                        "inputSchema",
                        "outputSchema",
                        "exitCodes",
                        "cliExample",
                        "restEndpoint",
                        "sideEffects",
                    ],
                    "properties": {
                        "name": {"type": "string"},
                        "category": {
                            "type": "string",
                            "enum": ["query", "mutation", "transform", "job", "introspection"],
                        },
                        "inputSchema": {"type": "object"},
                        "outputSchema": {"type": "object"},
                        "exitCodes": {"type": "object"},
                        "cliExample": {"type": "string"},
                        "restEndpoint": {
                            "type": "object",
                            "required": ["method", "path"],
                            "properties": {
                                "method": {"type": "string", "enum": ["GET", "POST"]},
                                "path": {"type": "string"},
                            },
                        },
                        "sideEffects": {
                            "type": "string",
                            "enum": ["none", "mutates-kernel", "enqueues-job", "writes-audit"],
                        },
                        "agentSafetyNotes": {"type": "string"},
                    },
                }
            },
        },
        exitCodes={"ok": ExitCode(code=0, meaning="Success")},
        cliExample="bim-ai api list-tools --output json",
        restEndpoint=RestEndpoint(method="GET", path="/api/v3/tools"),
        sideEffects="none",
        agentSafetyNotes="Safe to call freely; read-only, no kernel side-effects.",
    )
)

register(
    ToolDescriptor(
        name="api-inspect",
        category="introspection",
        inputSchema={
            "$schema": "http://json-schema.org/draft-07/schema#",
            "title": "ApiInspectInput",
            "type": "object",
            "required": ["name"],
            "properties": {
                "name": {"type": "string", "description": "Tool name to inspect."},
                "output": {
                    "type": "string",
                    "enum": ["json", "text"],
                    "default": "json",
                },
            },
            "additionalProperties": False,
        },
        outputSchema={
            "$schema": "http://json-schema.org/draft-07/schema#",
            "title": "ToolDescriptor",
            "$ref": "#/definitions/ToolDescriptor",
            "definitions": {
                "ToolDescriptor": {
                    "type": "object",
                    "required": ["name", "category"],
                    "properties": {
                        "name": {"type": "string"},
                        "category": {"type": "string"},
                    },
                }
            },
        },
        exitCodes=_COMMON_ERROR_CODES,
        cliExample="bim-ai api inspect api-list-tools --output json",
        restEndpoint=RestEndpoint(method="GET", path="/api/v3/tools/{name}"),
        sideEffects="none",
        agentSafetyNotes="Safe to call freely; read-only, no kernel side-effects.",
    )
)

register(
