368	function validateHouseBrief(blob) {
369	  const errors = [];
370	  if (!blob || typeof blob !== 'object') {
371	    errors.push('brief must be a JSON object');
372	    return errors;
373	  }
374	  if (typeof blob.version !== 'string') errors.push('version (string)');
375	  if (blob.stylePreset != null && typeof blob.stylePreset !== 'string')
376	    errors.push('stylePreset (optional string)');
377	  if (!Number.isFinite(blob.siteWidthM)) errors.push('siteWidthM (number)');
378	  if (!Number.isFinite(blob.siteDepthM)) errors.push('siteDepthM (number)');
379	  const floors = blob.floors;
380	  if (!Number.isInteger(floors) || floors < 1) errors.push('floors (int >= 1)');
381	  const rooms = blob.rooms;
382	  if (!Array.isArray(rooms) || rooms.length === 0) errors.push('rooms (non-empty array)');
383	  else {
384	    rooms.forEach((r, i) => {
385	      if (!r || typeof r !== 'object') errors.push(`rooms[${i}] object`);
386	      else {
387	        if (typeof r.name !== 'string') errors.push(`rooms[${i}].name`);
388	        if (!Number.isFinite(r.areaTargetM2)) errors.push(`rooms[${i}].areaTargetM2`);
389	      }
390	    });
391	  }
392	  return errors;
393	}
