506	function diffToText(diff) {
507	  const lines = [];
508	  lines.push(
509	    `# bim-ai diff  rev ${diff.fromRevision} -> ${diff.toRevision}  (model ${diff.modelId})`,
510	  );
511	  const s = diff.summary ?? {};
512	  lines.push(
513	    `# added=${s.addedCount ?? 0} removed=${s.removedCount ?? 0} modified=${s.modifiedCount ?? 0}`,
514	  );
515	  for (const a of diff.added ?? []) {
516	    const name = a && typeof a.name === 'string' ? a.name : '';
517	    lines.push(`+ ${a?.kind ?? '?'} ${a?.id ?? '?'}${name ? ` (${name})` : ''}`);
518	  }
519	  for (const r of diff.removed ?? []) {
520	    const name = r && typeof r.name === 'string' ? r.name : '';
521	    lines.push(`- ${r?.kind ?? '?'} ${r?.id ?? '?'}${name ? ` (${name})` : ''}`);
522	  }
523	  for (const m of diff.modified ?? []) {
524	    lines.push(`* ${m?.kind ?? '?'} ${m?.id ?? '?'}`);
525	    for (const fc of m?.fieldChanges ?? []) {
526	      lines.push(`    ${fc.field}: ${JSON.stringify(fc.from)} -> ${JSON.stringify(fc.to)}`);
527	    }
528	  }
529	  return `${lines.join('\n')}\n`;
530	}
