573	function summariseValidate(val) {
574	  const violations = Array.isArray(val?.violations) ? val.violations : [];
575	  let blocking = 0;
576	  for (const v of violations) {
577	    const sev = String(v?.severity ?? v?.level ?? '').toLowerCase();
578	    if (['blocking', 'block', 'error', 'critical', 'high'].includes(sev)) blocking++;
579	  }
580	  return { violationCount: violations.length, blockingCount: blocking };
581	}
