609	async function cmdAgentLoop(modelId, goalPath, maxIter, evidenceOut, backendOverride) {
610	  if (!modelId) {
611	    console.error('agent-loop requires BIM_AI_MODEL_ID');
612	    process.exit(1);
613	  }
614	  if (!goalPath) {
615	    console.error('agent-loop requires --goal <path>');
616	    process.exit(1);
617	  }
618	  const goalText = await readGoalText(goalPath);
619	  await fs.mkdir(evidenceOut, { recursive: true });
620	
621	  let lastScore = -Infinity;
622	  for (let iter = 1; iter <= maxIter; iter++) {
623	    const iterDir = path.join(evidenceOut, `iter-${String(iter).padStart(2, '0')}`);
624	    await fs.mkdir(iterDir, { recursive: true });
625	
626	    const snap = await fetchJson('GET', `${base}/api/models/${encodeURIComponent(modelId)}/snapshot`);
627	    const val = await fetchJson('GET', `${base}/api/models/${encodeURIComponent(modelId)}/validate`);
628	    const evidence = {
629	      revision: snap.revision ?? null,
630	      elementCount: snap.elements ? Object.keys(snap.elements).length : 0,
631	      validate: summariseValidate(val),
632	    };
633	    await fs.writeFile(path.join(iterDir, 'snapshot.json'), JSON.stringify(snap, null, 2));
634	    await fs.writeFile(path.join(iterDir, 'validate.json'), JSON.stringify(val, null, 2));
635	    await fs.writeFile(path.join(iterDir, 'evidence.json'), JSON.stringify(evidence, null, 2));
636	
637	    const baselineScore = progressScore(goalText, snap, val);
638	
639	    const patchResp = await agentIterate(modelId, goalText, snap, val, evidence, iter, backendOverride);
640	    await fs.writeFile(path.join(iterDir, 'patch.json'), JSON.stringify(patchResp, null, 2));
641	
642	    const commands = Array.isArray(patchResp.patch) ? patchResp.patch : [];
643	    if (!commands.length) {
644	      const status = {
645	        status: 'no-patch',
646	        iteration: iter,
647	        rationale: patchResp.rationale ?? '',
648	        confidence: patchResp.confidence ?? 0,
649	      };
