655	    const dryUrl = `${base}/api/models/${encodeURIComponent(modelId)}/commands/bundle/dry-run`;
656	    const dryResp = await fetch(dryUrl, {
657	      method: 'POST',
658	      headers: { 'content-type': 'application/json' },
659	      body: JSON.stringify({ commands, userId: 'agent-loop' }),
660	    });
661	    const dryText = await dryResp.text();
662	    let dryJson;
663	    try {
664	      dryJson = JSON.parse(dryText);
665	    } catch {
666	      dryJson = { raw: dryText };
667	    }
668	    await fs.writeFile(path.join(iterDir, 'dry-run.json'), JSON.stringify(dryJson, null, 2));
669	    if (!dryResp.ok) {
670	      const status = { status: 'dry-run-failed', iteration: iter, body: dryJson };
671	      await fs.writeFile(path.join(iterDir, 'status.json'), JSON.stringify(status, null, 2));
672	      console.log(JSON.stringify({ ok: false, iteration: iter, status: 'dry-run-failed' }, null, 2));
673	      return;
674	    }
675	
676	    const applyResp = await fetchJson(
677	      'POST',
678	      `${base}/api/models/${encodeURIComponent(modelId)}/commands/bundle`,
679	      { commands, userId: 'agent-loop' },
680	    );
681	    await fs.writeFile(path.join(iterDir, 'apply.json'), JSON.stringify(applyResp, null, 2));
