694	    const newScore = progressScore(goalText, snap2, val2);
695	    const progressed = newScore > Math.max(baselineScore, lastScore);
696	    const regressed = newScore < baselineScore;
697	
698	    const status = {
699	      status: progressed ? 'progress' : regressed ? 'regression-rolled-back' : 'no-progress',
700	      iteration: iter,
701	      baselineScore,
702	      newScore,
703	      rationale: patchResp.rationale ?? '',
