@api_router.post("/jobs", status_code=201)
async def create_job(
    body: CreateJobRequest,
    queue: JobQueue = Depends(get_queue),
) -> dict:
    from datetime import datetime, timezone

    job = Job(
        model_id=body.model_id,
        kind=body.kind,
        inputs=body.inputs,
        created_at=datetime.now(timezone.utc).isoformat(),
    )
    submitted = await queue.submit(job)
    return submitted.model_dump(by_alias=True)


@api_router.get("/jobs")
async def list_jobs(
    model_id: str,
    queue: JobQueue = Depends(get_queue),
) -> list[dict]:
    jobs = queue.list_for_model(model_id)
    return [j.model_dump(by_alias=True) for j in jobs]


@api_router.get("/jobs/{job_id}")
async def get_job(
    job_id: str,
    queue: JobQueue = Depends(get_queue),
) -> dict:
    job = queue.get(job_id)
    if job is None:
        raise HTTPException(status_code=404, detail="job not found")
    return job.model_dump(by_alias=True)


@api_router.post("/jobs/{job_id}/cancel")
async def cancel_job(
    job_id: str,
    queue: JobQueue = Depends(get_queue),
) -> dict:
    job = queue.get(job_id)
    if job is None:
        raise HTTPException(status_code=404, detail="job not found")
    if job.status not in ("queued", "running"):
        raise HTTPException(status_code=409, detail="job cannot be cancelled")
    updated = await queue.update_status(job_id, "cancelled")
    return updated.model_dump(by_alias=True)


