if (cmd === 'view-set-phase-filter') {
  if (!modelId) usage();
  const viewId = argv[argv.indexOf('--view-id') + 1];
  const phaseFilter = argv[argv.indexOf('--phase-filter') + 1];
  if (!viewId || !phaseFilter) { console.error('view-set-phase-filter requires --view-id <id> --phase-filter <filter>'); process.exit(1); }
  await postCommand(modelId, userId, { type: 'setViewPhaseFilter', viewId, phaseFilter });
  return;
}

if (cmd === 'jobs') {
  const sub = argv[1];
  const rest = argv.slice(2);

  if (sub === 'submit') {
    const kind = rest[0];
    if (!kind) {
      console.error('jobs submit requires <kind>');
      process.exit(1);
    }
    let jobModelId = modelId;
    let inputsArg = '{}';
    for (let i = 1; i < rest.length; i++) {
      if (rest[i] === '--model' && rest[i + 1]) jobModelId = rest[++i];
      else if (rest[i] === '--inputs' && rest[i + 1]) inputsArg = rest[++i];
    }
    if (!jobModelId) {
      console.error('jobs submit requires --model <id> or BIM_AI_MODEL_ID');
      process.exit(1);
    }
    let inputs;
    try {
      inputs = JSON.parse(inputsArg);
    } catch {
      console.error(`Invalid --inputs JSON: ${inputsArg}`);
      process.exit(1);
    }
    const json = await fetchJson('POST', `${base}/api/jobs`, {
      kind,
      modelId: jobModelId,
      inputs,
    });
    console.log(JSON.stringify(json, null, 2));
    return;
  }

  if (sub === 'list') {
    let jobModelId = modelId;
    let wait = false;
    for (let i = 0; i < rest.length; i++) {
      if (rest[i] === '--model' && rest[i + 1]) jobModelId = rest[++i];
      else if (rest[i] === '--wait') wait = true;
    }
    if (!jobModelId) {
      console.error('jobs list requires --model <id> or BIM_AI_MODEL_ID');
      process.exit(1);
    }
    if (wait) {
      let done = false;
      while (!done) {
        const jobs = await fetchJson('GET', `${base}/api/jobs?modelId=${encodeURIComponent(jobModelId)}`);
        const active = jobs.filter((j) => j.status === 'queued' || j.status === 'running');
        if (active.length === 0) { done = true; } else {
          await new Promise((r) => setTimeout(r, 1000));
        }
      }
    }
    const json = await fetchJson('GET', `${base}/api/jobs?modelId=${encodeURIComponent(jobModelId)}`);
    console.log(JSON.stringify(json, null, 2));
    return;
  }

  if (sub === 'cancel') {
    const jobId = rest[0];
    if (!jobId) { console.error('jobs cancel requires <job-id>'); process.exit(1); }
    const json = await fetchJson('POST', `${base}/api/jobs/${encodeURIComponent(jobId)}/cancel`);
    console.log(JSON.stringify(json, null, 2));
    return;
  }

  if (sub === 'status') {
    const jobId = rest[0];
    if (!jobId) { console.error('jobs status requires <job-id>'); process.exit(1); }
    const json = await fetchJson('GET', `${base}/api/jobs/${encodeURIComponent(jobId)}`);
    console.log(JSON.stringify(json, null, 2));
    return;
  }

  console.error(`Unknown jobs subcommand: ${sub ?? '(none)'}. Use submit | list | cancel | status.`);
  process.exit(1);
}

